import json
from autogen import UserProxyAgent

class RecordingProxy(UserProxyAgent):
    def __init__(self, *args, record_path="inputs.json", **kwargs):
        super().__init__(*args, **kwargs)
        self._record_path = record_path
        self._recorded = []

    def get_human_input(self, prompt: str) -> str:
        response = super().get_human_input(prompt)
        self._recorded.append(response)
        return response

    def save_recording(self):
        with open(self._record_path, "w") as f:
            json.dump(self._recorded, f)

class ReplayProxy(UserProxyAgent):
    def __init__(self, *args, record_path="inputs.json", **kwargs):
        super().__init__(*args, **kwargs)
        with open(record_path) as f:
            self._replies = json.load(f)

    def get_human_input(self, prompt: str) -> str:
        return self._replies.pop(0) if self._replies else "exit"
